// Etsy Receipt → orders-Schema transformieren
const results = $input.item.json.results ?? [];

return results.map(r => {
  // Etsy speichert Geldbeträge als { amount, divisor, currency_code }
  const money = (obj) => obj ? (obj.amount / obj.divisor) : null;

  // Status-Mapping Etsy → internes Schema
  const statusMap = {
    'paid':      'paid',
    'open':      'paid',
    'completed': 'completed',
    'shipped':   'shipped',
    'canceled':  'cancelled',
  };

  // Items aus transactions extrahieren
  const items = (r.transactions ?? []).map(t => ({
    listing_id:  t.listing_id,
    title:       t.title,
    quantity:    t.quantity,
    price:       money(t.price),
    is_digital:  t.is_digital ?? false,
  }));

  const isDigital = items.every(i => i.is_digital);

  return {
    json: {
      order_id:      String(r.receipt_id),
      source:        'etsy',
      order_date:    new Date(r.created_timestamp * 1000).toISOString(),
      buyer_name:    r.name ?? null,
      buyer_email:   r.buyer_email ?? null,
      buyer_street:  r.first_line ?? null,
      buyer_city:    r.city ?? null,
      buyer_zip:     r.zip ?? null,
      buyer_country: r.country_iso ?? null,
      items_json:    JSON.stringify(items),
      subtotal:      money(r.subtotal),
      shipping_cost: money(r.total_shipping_cost),
      total:         money(r.grandtotal),
      currency:      r.currency_code ?? 'EUR',
      status:        statusMap[r.status] ?? 'paid',
      is_digital:    isDigital,
    }
  };
});
